example.code:
{
  "artefact_id": "billing-app-router",
  "owner": "ruslan@faion.net",
  "app_name": "billing",
  "next_version": "^15.0.0",
  "react_version": "^19.0.0",
  "ts_version": "^5.4.0",
  "routes": [
    {
      "path": "/dashboard",
      "files": [
        {"file": "app/dashboard/layout.tsx",       "boundary": "server-default"},
        {"file": "app/dashboard/page.tsx",         "boundary": "server-default"},
        {"file": "app/dashboard/loading.tsx",      "boundary": "server-default"},
        {"file": "app/dashboard/error.tsx",        "boundary": "use-client", "uses_hooks": true},
        {"file": "app/dashboard/Sidebar.tsx",      "boundary": "use-client", "uses_hooks": true},
        {"file": "app/dashboard/InvoiceForm.tsx",  "boundary": "use-client", "uses_hooks": true},
        {"file": "app/dashboard/actions.ts",       "boundary": "use-server"}
      ]
    }
  ],
  "actions": [
    {"name": "createInvoice", "mutates": true, "revalidate": {"kind": "path", "target": "/dashboard"}, "input_schema": "CreateInvoiceSchema"}
  ],
  "tsconfig_flags": {"strict": true, "noUncheckedIndexedAccess": true, "exactOptionalPropertyTypes": true, "verbatimModuleSyntax": true},
  "version": "1.0.0",
  "last_reviewed": "2026-05-22"
}
